// Parse subscribers from Google Sheets and extract all unique categories
const subscribers = items.map(item => {
  const row = item.json;

  // Find fields by checking multiple possible column names
  const findField = (obj, ...keys) => {
    // First try exact matches
    for (const k of keys) {
      if (obj[k] !== undefined) return obj[k];
    }
    // Then try case-insensitive partial matches
    const objKeys = Object.keys(obj);
    for (const k of keys) {
      const lower = k.toLowerCase();
      const match = objKeys.find(ok => ok.toLowerCase().includes(lower));
      if (match && obj[match] !== undefined) return obj[match];
    }
    return '';
  };

  const name = String(findField(row, 'Name', 'name')).trim();
  const email = String(findField(row, 'Email', 'email')).trim();
  const keywords = String(findField(row, 'Keywords', 'keywords')).trim();
  const categoriesRaw = String(findField(row, 'Categories', 'categories', 'ArXiv Categories')).trim();
  const status = String(findField(row, 'Status', 'status')).trim().toLowerCase();

  return {
    name,
    email,
    keywords,
    categories: categoriesRaw.split(',').map(c => c.trim()).filter(Boolean),
    status,
  };
});

// Filter active users
const activeSubscribers = subscribers.filter(s =>
  s.status === 'active' && s.email && s.keywords && s.categories.length > 0
);

if (activeSubscribers.length === 0) {
  return [{
    json: {
      error: 'No active subscribers found in Google Sheet',
      subscribers: [],
      allCategories: [],
    }
  }];
}

// Collect all unique categories across all active subscribers
const allCategories = [...new Set(activeSubscribers.flatMap(s => s.categories))];

return [{
  json: {
    subscribers: activeSubscribers,
    allCategories: allCategories,
    subscriberCount: activeSubscribers.length,
    workflowStartTime: Date.now(),
  }
}];

const scrapeResponse = items[0].json;
const subscriberData = $('Parse Subscribers & Categories').first().json;

const totalPapers = scrapeResponse.total_unique_papers || 0;
const hasError = !!scrapeResponse.error;
const noPapers = hasError || totalPapers === 0;

return [{
  json: {
    noPapers: noPapers,
    errorMessage: hasError ? ('Scrape error: ' + scrapeResponse.error) : (noPapers ? 'No papers found in any RSS feed' : ''),
    scrapeMetrics: scrapeResponse.metrics || {},
    papersByCategory: scrapeResponse.papers_by_category || {},
    totalUniquePapers: totalPapers,
    subscribers: subscriberData.subscribers || [],
    subscriberCount: subscriberData.subscriberCount || 0,
    allCategories: subscriberData.allCategories || [],
    workflowStartTime: subscriberData.workflowStartTime || Date.now(),
  }
}];

// Split subscribers into individual items for the person loop
// If no papers were found, return empty array (Person Loop skips to done)
const data = items[0].json;

if (data.noPapers) {
  // Return empty - Person Loop will immediately go to "done" output
  return [];
}

const subscribers = data.subscribers || [];
return subscribers.map(sub => ({
  json: {
    person: sub,
    scrapeMetrics: data.scrapeMetrics,
    papersByCategory: data.papersByCategory,
    totalUniquePapers: data.totalUniquePapers,
    workflowStartTime: data.workflowStartTime,
  }
}));

const scoreResponse = items[0].json;
const personData = $('Person Loop').first().json;
const person = personData.person;
const scrapeMetrics = personData.scrapeMetrics;
const workflowStartTime = personData.workflowStartTime;

const papers = scoreResponse.papers || [];
const totalInCategories = scoreResponse.total_in_categories || 0;

if (papers.length === 0) {
  // No papers for this person - return empty to skip to next person
  return [];
}

return [{
  json: {
    person: person,
    papers: papers,
    totalInCategories: totalInCategories,
    scoringTime: scoreResponse.scoring_time,
    scrapeMetrics: scrapeMetrics,
    totalUniquePapers: personData.totalUniquePapers,
    workflowStartTime: workflowStartTime,
  }
}];

// Split the scored papers into individual items for LLM summarization
const data = items[0].json;
const papers = data.papers || [];

return papers.map(paper => ({
  json: {
    ...paper,
    person: data.person,
    scrapeMetrics: data.scrapeMetrics,
    totalInCategories: data.totalInCategories,
    totalUniquePapers: data.totalUniquePapers,
    workflowStartTime: data.workflowStartTime,
  }
}));

const paper = $json;
const person = paper.person;

const relevancePercent = (paper.relevance_score * 100).toFixed(1);

const prompt = `Summarize this scientific paper. First provide a brief 2-3 sentence overview, then detailed bullet points.
This summary is for ${person.name}, whose research interests include: ${person.keywords}

**OUTPUT FORMAT (use exactly this structure):**

[Write a 2-3 sentence paragraph that gives a plain-language overview of the paper's main contribution, methodology, and key finding. This should provide a quick snapshot for a busy researcher. Do NOT use a heading for this paragraph.]

- **Key Result:** [One sentence: the main finding or contribution]
- **Method:** [One sentence: the approach or technique used]
- **Findings:**
  - [Specific result 1 with numbers if available]
  - [Specific result 2]
  - [Specific result 3 if applicable]
- **Relevance to ${person.name}:** [One sentence: how this connects to their research interests]

---

**Title:** ${paper.title}

**Abstract:** ${paper.abstract}

**Relevance Score:** ${relevancePercent}% (cosine similarity to research keywords)

---

**RULES:**
- Start with the overview paragraph (2-3 sentences, no heading, just plain text)
- Leave a blank line between the paragraph and the bullet points
- Then list the bullet points using "- " prefix (dash + space)
- Be specific and technical, not generic
- Include quantitative results when available (thresholds, scaling, percentages)
- Maximum 200 words total (paragraph + bullets combined)
- Use "- " for all bullets, not bullet symbols
- The "Relevance" bullet should directly mention specific keywords from the person's interests`;

return {
  json: {
    ...paper,
    chatInput: prompt
  }
};

const originalPapers = $('Prepare Personalized LLM Prompt').all();
