  return {
    rank: original.rank || index + 1,
    title: original.title || 'Untitled',
    authors: original.authors || 'Unknown',
    abstract: original.abstract || '',
    link: original.link || '#',
    pdfLink: original.pdf_link || '#',
    llmSummary: item.json.text || item.json.output || 'Summary not available',
    relevanceScore: original.relevance_score || 0,
    published: original.published || '',
    updated: original.updated || '',
    pages: original.pages,
    readingTimeMin: original.reading_time_min,
    arxivId: original.arxiv_id || '',
    comment: original.comment || '',
    categories: original.categories || [],
  };
});

processedPapers.sort((a, b) => a.rank - b.rank);

const scrapeMetrics = originalPapers[0]?.json?.scrapeMetrics || {};
const workflowStartTime = parseInt(originalPapers[0]?.json?.workflowStartTime) || Date.now();
const totalInCategories = originalPapers[0]?.json?.totalInCategories || 0;
const totalUniquePapers = originalPapers[0]?.json?.totalUniquePapers || 0;

return [{
