const formatTime = (ms) => {
  if (!ms || ms < 0) return '?';
  const min = Math.floor(ms / 60000);
  const sec = Math.floor((ms % 60000) / 1000);
  return min > 0 ? `${min}m ${sec}s` : `${sec}s`;
};

const formatSeconds = (s) => {
  if (!s || s < 0) return '?';
  const min = Math.floor(s / 60);
  const sec = Math.round(s % 60);
  return min > 0 ? `${min}m ${sec}s` : `${sec}s`;
};

