    const t = ln.trim();
    if (!foundBullet && (t.startsWith('- **') || t.startsWith('* **') || /^\u2022/.test(t))) {
      foundBullet = true;
    }
    if (foundBullet) {
      bulletParts.push(ln);
    } else if (t.length > 0) {
      paragraphParts.push(ln);
    }
  }

  const overviewHtml = paragraphParts.join(' ')
    .replace(/\*\*([^*]+)\*\*/g, '<strong style="color:#1e3a5f;">$1</strong>');

  const bulletsHtml = bulletParts.join('\n')
    .replace(/\*\*([^*]+)\*\*/g, '<strong style="color:#1e3a5f;">$1</strong>')
    .replace(/^[\u2022\-\*]\s*/gm, '&bull; ')
    .replace(/\n/g, '<br>');

