      <div class="paper-links" style="margin-bottom:10px;">
        <a href="${paper.link}" target="_blank" style="display:inline-block;font-size:12px;color:#2d5a87;text-decoration:none;margin-right:12px;padding:4px 10px;background-color:#e8f4f8;border-radius:4px;">Abstract</a>
        <a href="${paper.pdfLink}" target="_blank" style="display:inline-block;font-size:12px;color:#2d5a87;text-decoration:none;padding:4px 10px;background-color:#e8f4f8;border-radius:4px;">PDF</a>
      </div>
      <div class="paper-summary" style="font-size:14px;color:#333;line-height:1.6;background-color:#fafafa;padding:12px;border-radius:6px;margin-top:10px;">${overviewHtml ? '<div class="paper-overview" style="font-style:italic;color:#444;margin-bottom:10px;padding-bottom:8px;border-bottom:1px dashed #ddd;line-height:1.6;">' + overviewHtml + '</div>' : ''}${bulletsHtml}</div>
    </div>`;
}

html += `
  </div>

  <div class="footer" style="text-align:center;color:#888;font-size:12px;padding:20px;border-top:1px solid #e0e0e0;margin-top:20px;">
    <p><strong>Arxiv Research Daily Digest v10</strong></p>
    <p>Semantic ranking: SPECTER2 (CPU) | Summaries: Claude Haiku 4.5 | Paragraph + Bullets | Inline Styles</p>
    <p style="font-size:11px;color:#aaa;">
      Papers scanned: ${totalUniquePapers || '?'} &middot;
      Your categories: ${categoriesList.join(', ')} &middot;
      Total time: ${formatTime(totalWorkflowMs)}
    </p>
  </div>
</body>
</html>`;

return [{
  json: {
    newsletterHtml: html,
    subject: `Research Digest - ${today} (Top ${papers.length} for ${person.name})`,
    person: person,
    paperCount: papers.length,
    totalInCategories: totalInCategories,
  }
}];
